import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface CompetitorPrice {
  store: string;
  price: number;
}

interface ProductData {
  product: {
    name: string;
    currentPrice: number;
    competitorPrices: CompetitorPrice[];
    priceTrend: number[];
  };
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const productData = response.data as ProductData;
  const metaData = response.meta as MetaData;
  const { product } = productData;
  const primaryColor = metaData.primaryColor;
  const accentColor = metaData.accentColor;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 350,
        maxWidth: 450,
        bgcolor: '#2E2E2E',
        color: '#FFFFFF'
      }}
      elevation={3}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 0.5, color: accentColor }}>
              {product.name}
            </Typography>
            <Typography variant="h4" sx={{ color: primaryColor, fontWeight: 600 }}>
              ${product.currentPrice}
            </Typography>
          </Box>

          <LineChart
            height={120}
            series={[
              {
                data: product.priceTrend,
                color: primaryColor,
                curve: 'natural',
                showMark: false,
              },
            ]}
            xAxis={[{ data: product.priceTrend.map((_, i) => i), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />

          <Stack direction="row" spacing={1.5} sx={{ flexWrap: 'wrap' }}>
            {product.competitorPrices.map((competitor) => (
              <Chip
                key={competitor.store}
                label={`${competitor.store}: $${competitor.price}`}
                sx={{ bgcolor: '#424242', color: '#FFFFFF', fontSize: '12px' }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
